const handleSubmit =
  async (e) => {

  e.preventDefault();

  try {

    const data =
      await loginUser(formData);

    localStorage.setItem(
      'token',
      data.token
    );

    // Teacher
    if (
      data.user.role ===
      'teacher'
    ) {

      navigate(
        '/teacher-dashboard'
      );

    }

    // Student
    else if (
      data.user.role ===
      'student'
    ) {

      navigate(
        '/student-dashboard'
      );

    }

    // Coordinator
    else {

      navigate(
        '/coordinator-dashboard'
      );

    }

  } catch (error) {

    alert(
      error.response?.data?.message
    );

  }

};
